import axios from "axios";
import React, { useState } from "react";
import toast from "react-hot-toast";
import { useNavigate } from "react-router-dom";
import { UserIcon, EnvelopeIcon, ArrowRightOnRectangleIcon } from "@heroicons/react/24/outline"; 
import { useSelector } from "react-redux";
const Profile = () => {
  const navigate = useNavigate();
  const [isLoggingOut, setIsLoggingOut] = useState(false); 
  const {authUser} = useSelector((store)=> sto)  


  const user = { username: "johnDoe", email: "johndoe@example.com" }; 
  const handleLogout = async () => {
    setIsLoggingOut(true);
    try {
      const response = await axios.get(
        "http://localhost:4000/api/user/logout",
        {
          withCredentials: true,
          headers: {
            "Content-Type": "application/json",
          },
        }
      );
      toast.success(response.data.message);
      localStorage.removeItem("jwt");
      navigate("/login");
    } catch (error) {
      console.error(error);
      toast.error("Logout failed. Please try again.");
    } finally {
      setIsLoggingOut(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
      <div className="max-w-lg mx-auto bg-white rounded-2xl shadow-xl overflow-hidden transform transition-all duration-300 hover:scale-105">
        <div className="p-8 text-center">
          {/* Profile Picture Placeholder */}
          <div className="flex justify-center mb-6">
            <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center">
              <UserIcon className="h-10 w-10 text-indigo-600" />
            </div>
          </div>

          {/* Title */}
          <h1 className="text-3xl font-bold text-gray-800 mb-2">My Profile</h1>
          <p className="text-gray-600 mb-8">Manage your account and settings</p>

          {/* User Information */}
          <div className="space-y-4 mb-8">
            <div className="flex items-center justify-center space-x-3 text-gray-700">
              <UserIcon className="h-5 w-5 text-indigo-500" />
              <span className="text-sm">
                Username: <span className="font-semibold text-gray-800">{user.username}</span>
              </span>
            </div>
            <div className="flex items-center justify-center space-x-3 text-gray-700">
              <EnvelopeIcon className="h-5 w-5 text-indigo-500" />
              <span className="text-sm">
                Email: <span className="font-semibold text-gray-800 underline">{user.email}</span>
              </span>
            </div>
          </div>

          {/* Logout Button */}
          <button
            onClick={handleLogout}
            disabled={isLoggingOut}
            className={`w-full py-3 px-6 rounded-lg font-semibold transition-colors duration-200 flex items-center justify-center space-x-2 ${
              isLoggingOut
                ? "bg-gray-400 text-gray-700 cursor-not-allowed"
                : "bg-red-500 text-white hover:bg-red-600"
            }`}
            aria-label="Logout"
          >
            <ArrowRightOnRectangleIcon className="h-5 w-5" />
            <span>{isLoggingOut ? "Logging out..." : "Logout"}</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Profile;
